1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>Modular All Drives — Supplier Follow-up Tracker</title>
7	<style>
8	  :root{
9	    --bg:#0f1115; --card:#181b22; --card2:#1f232c; --line:#2b303b;
10	    --txt:#e7eaf0; --mut:#9aa3b2; --accent:#3b82f6; --accent2:#1d4ed8;
11	    --green:#22c55e; --amber:#f59e0b; --red:#ef4444; --grey:#6b7280;
12	    --chip:#262b35;
13	  }
14	  *{box-sizing:border-box}
15	  body{margin:0;background:var(--bg);color:var(--txt);font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,Helvetica,Arial,sans-serif;line-height:1.5}
16	  header{padding:24px 28px 16px;border-bottom:1px solid var(--line);position:sticky;top:0;background:var(--bg);z-index:10}
17	  h1{margin:0;font-size:20px;font-weight:650}
18	  .sub{color:var(--mut);font-size:13px;margin-top:4px}
19	  .bar{display:flex;gap:10px;flex-wrap:wrap;margin-top:16px;align-items:center}
20	  .pill{background:var(--chip);border:1px solid var(--line);border-radius:20px;padding:5px 12px;font-size:12px;color:var(--mut);cursor:pointer;user-select:none}
21	  .pill.active{background:var(--accent2);border-color:var(--accent);color:#fff}
22	  .counts{margin-left:auto;display:flex;gap:14px;font-size:12px;color:var(--mut)}
23	  .counts b{color:var(--txt)}
24	  main{padding:20px 28px 80px;max-width:1100px;margin:0 auto}
25	  .card{background:var(--card);border:1px solid var(--line);border-radius:14px;margin-bottom:14px;overflow:hidden}
26	  .chead{display:flex;align-items:center;gap:12px;padding:14px 18px;cursor:pointer}
27	  .chead:hover{background:var(--card2)}
28	  .name{font-weight:650;font-size:15px}
29	  .meta{color:var(--mut);font-size:12px}
30	  .spacer{flex:1}
31	  .status{font-size:11px;font-weight:600;padding:4px 10px;border-radius:20px;white-space:nowrap}
32	  .s-wait{background:rgba(245,158,11,.15);color:var(--amber)}
33	  .s-action{background:rgba(239,68,68,.15);color:var(--red)}
34	  .s-done{background:rgba(34,197,94,.15);color:var(--green)}
35	  .s-alisson{background:rgba(168,85,247,.18);color:#c084fc}
36	  .s-sched{background:rgba(59,130,246,.18);color:#60a5fa}
37	  .next{font-size:12px;color:var(--txt);background:var(--chip);border:1px solid var(--line);padding:3px 9px;border-radius:8px;max-width:340px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
38	  .arrow{color:var(--mut);transition:transform .15s;font-size:12px}
39	  .card.open .arrow{transform:rotate(90deg)}
40	  .body{display:none;padding:4px 18px 18px;border-top:1px solid var(--line)}
41	  .card.open .body{display:block}
42	  .sec{margin-top:14px}
43	  .sec h4{margin:0 0 6px;font-size:12px;letter-spacing:.04em;text-transform:uppercase;color:var(--mut)}
44	  ul{margin:0;padding-left:18px}
45	  li{margin:3px 0;font-size:13.5px}
46	  .todo{list-style:none;padding:0}
47	  .todo li{display:flex;gap:9px;align-items:flex-start;padding:6px 0;border-bottom:1px solid var(--line)}
48	  .todo li:last-child{border-bottom:none}
49	  .todo input{margin-top:3px;width:16px;height:16px;accent-color:var(--green);cursor:pointer;flex-shrink:0}
50	  .todo label{cursor:pointer;flex:1}
51	  .todo li.checked label{text-decoration:line-through;color:var(--mut)}
52	  .del{background:none;border:none;color:var(--grey);cursor:pointer;font-size:15px;padding:0 4px;flex-shrink:0;line-height:1;opacity:.55}
53	  .del:hover{color:var(--red);opacity:1}
54	  .addrow{display:flex;gap:8px;margin-top:10px}
55	  .addrow input{flex:1;background:var(--card2);color:var(--txt);border:1px solid var(--line);border-radius:8px;padding:8px 10px;font-size:13px;font-family:inherit}
56	  .addbtn{background:var(--accent2);border:1px solid var(--accent);color:#fff;border-radius:8px;padding:8px 14px;font-size:13px;cursor:pointer;white-space:nowrap}
57	  .addbtn:hover{background:var(--accent)}
58	  .ctrls{display:flex;gap:10px;flex-wrap:wrap;margin-top:16px;align-items:center}
59	  select,textarea{background:var(--card2);color:var(--txt);border:1px solid var(--line);border-radius:8px;padding:8px 10px;font-size:13px;font-family:inherit}
60	  select{cursor:pointer}
61	  textarea{width:100%;min-height:60px;resize:vertical;margin-top:6px}
62	  .lbl{font-size:11px;color:var(--mut);text-transform:uppercase;letter-spacing:.04em}
63	  .tag{display:inline-block;font-size:11px;background:var(--chip);border:1px solid var(--line);border-radius:6px;padding:2px 8px;color:var(--mut);margin:2px 4px 2px 0}
64	  .saveflash{font-size:11px;color:var(--green);opacity:0;transition:opacity .3s}
65	  .saveflash.show{opacity:1}
66	  footer{color:var(--mut);font-size:11px;text-align:center;padding:0 28px 40px}
67	  a{color:#60a5fa}
68	</style>
69	</head>
70	<body>
71	<header>
72	  <h1>Modular All Drives — Supplier Follow-up Tracker</h1>
73	  <div class="sub">EOL test system (hipot · functional · load) for WEG VFDs · Aluizio Kleine, Industrial Engineering</div>
74	  <div class="bar">
75	    <span class="pill active" data-f="all">All</span>
76	    <span class="pill" data-f="action">⚠ I must act</span>
77	    <span class="pill" data-f="wait">⏳ Waiting on them</span>
78	    <span class="pill" data-f="sched">📅 To schedule</span>
79	    <span class="pill" data-f="alisson">🟣 Alissonn must act</span>
80	    <span class="pill" data-f="done">✓ Done</span>
